const channel = $('Get Channel Statistics').first().json;
const videos = $('Get Last 4 Videos').all();

const subs    = parseInt(channel.statistics?.subscriberCount || 0);
const views   = parseInt(channel.statistics?.viewCount || 0);
const totalVids = parseInt(channel.statistics?.videoCount || 0);

let videoLines = '';
for (const v of videos) {
  const s = v.json.statistics || {};
  const title = v.json.snippet?.title || 'Unknown';
  const vViews = parseInt(s.viewCount || 0);
  const likes  = parseInt(s.likeCount || 0);
  const comments = parseInt(s.commentCount || 0);
  const ctr = vViews > 0 ? ((likes / vViews) * 100).toFixed(2) : '0.00';
  videoLines += `\n📹 **${title}**\n   👁 Views: ${vViews.toLocaleString()} | 👍 Likes: ${likes.toLocaleString()} | 💬 Comments: ${comments} | Engagement: ${ctr}%\n`;
}

return [{ json: {
  subscribers: subs.toLocaleString(),
  totalViews:  views.toLocaleString(),
  totalVideos: totalVids,
  videoLines,
  date: new Date().toDateString()
}}];

